import React, { useState, useEffect } from 'react';
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Box,
  Alert,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  CircularProgress,
  Fade,
  Slide,
  Zoom,
  useTheme,
  useMediaQuery
} from '@mui/material';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { motion } from 'framer-motion';
import ParticlesBackground from './ParticlesBackground'; // You'll need to implement this or use a package

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState<'student' | 'faculty'>('student');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [shake, setShake] = useState(false);
  const [mounted, setMounted] = useState(false);

  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

  const { login } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    setMounted(true);
    return () => setMounted(false);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login(email, password);
      navigate(role === 'student' ? '/student/dashboard' : '/faculty/dashboard');
    } catch (err: any) {
      setError(err.message || 'Failed to login');
      setShake(true);
      setTimeout(() => setShake(false), 500);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
        position: 'relative',
        overflow: 'hidden'
      }}
    >
      {/* Animated background particles */}
      <ParticlesBackground />

      <Container maxWidth="sm">
        <Slide direction="down" in={mounted} mountOnEnter unmountOnExit>
          <Paper
            elevation={6}
            component={motion.div}
            animate={{
              y: shake ? [0, 10, -10, 10, -5, 5, 0] : 0,
            }}
            transition={{ duration: 0.5 }}
            sx={{
              padding: isMobile ? 3 : 4,
              borderRadius: 4,
              backdropFilter: 'blur(10px)',
              backgroundColor: 'rgba(255, 255, 255, 0.85)',
              boxShadow: '0 8px 32px 0 rgba(31, 38, 135, 0.15)',
              border: '1px solid rgba(255, 255, 255, 0.18)',
              position: 'relative',
              overflow: 'hidden',
              '&:before': {
                content: '""',
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                height: '4px',
                background: 'linear-gradient(90deg, #3f51b5, #2196f3, #00bcd4)',
              }
            }}
          >
            <Fade in={mounted}>
              <Box>
                <Box textAlign="center" mb={4}>
                  <Zoom in={mounted}>
                    <Typography 
                      component="h1" 
                      variant="h4" 
                      sx={{
                        fontWeight: 700,
                        background: 'linear-gradient(90deg, #3f51b5, #2196f3)',
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                        mb: 1
                      }}
                    >
                      Welcome Back
                    </Typography>
                  </Zoom>
                  <Typography 
                    variant="subtitle1" 
                    color="textSecondary"
                    sx={{ opacity: 0.8 }}
                  >
                    Sign in to access your QR Attendance System
                  </Typography>
                </Box>

                {error && (
                  <Fade in={!!error}>
                    <Alert 
                      severity="error" 
                      sx={{ 
                        width: '100%', 
                        mb: 3,
                        borderRadius: 2
                      }}
                    >
                      {error}
                    </Alert>
                  </Fade>
                )}

                <Box 
                  component="form" 
                  onSubmit={handleSubmit}
                  sx={{ 
                    '& .MuiTextField-root': { mb: 2 },
                    '& .MuiFormControl-root': { mb: 2 }
                  }}
                >
                  <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                  >
                    <TextField
                      fullWidth
                      variant="outlined"
                      label="Email Address"
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      disabled={loading}
                      sx={{
                        '& .MuiOutlinedInput-root': {
                          borderRadius: 2,
                          '& fieldset': {
                            borderColor: 'rgba(0, 0, 0, 0.23)',
                          },
                          '&:hover fieldset': {
                            borderColor: theme.palette.primary.main,
                          },
                        },
                      }}
                    />
                  </motion.div>

                  <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                  >
                    <TextField
                      fullWidth
                      variant="outlined"
                      label="Password"
                      type="password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      disabled={loading}
                      sx={{
                        '& .MuiOutlinedInput-root': {
                          borderRadius: 2,
                        },
                      }}
                    />
                  </motion.div>

                  <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                  >
                    <FormControl fullWidth>
                      <InputLabel>Role</InputLabel>
                      <Select
                        value={role}
                        label="Role"
                        onChange={(e) => setRole(e.target.value as 'student' | 'faculty')}
                        disabled={loading}
                        sx={{
                          borderRadius: 2,
                          '& .MuiOutlinedInput-root': {
                            borderRadius: 2,
                          },
                        }}
                      >
                        <MenuItem value="student">Student</MenuItem>
                        <MenuItem value="faculty">Faculty</MenuItem>
                      </Select>
                    </FormControl>
                  </motion.div>

                  <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.4 }}
                  >
                    <Button
                      type="submit"
                      fullWidth
                      variant="contained"
                      size="large"
                      disabled={loading}
                      sx={{
                        mt: 2,
                        py: 1.5,
                        borderRadius: 2,
                        fontSize: '1rem',
                        fontWeight: 600,
                        textTransform: 'none',
                        boxShadow: 'none',
                        '&:hover': {
                          boxShadow: '0 4px 12px rgba(63, 81, 181, 0.3)',
                          transform: 'translateY(-2px)',
                        },
                        transition: 'all 0.3s ease',
                      }}
                    >
                      {loading ? (
                        <CircularProgress size={24} color="inherit" />
                      ) : (
                        'Sign In'
                      )}
                    </Button>
                  </motion.div>
                </Box>

                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.5 }}
                >
                  <Box sx={{ mt: 3, textAlign: 'center' }}>
                    <Typography variant="body2" color="textSecondary">
                      Don't have an account?{' '}
                      <Link 
                        to="/register" 
                        style={{ 
                          textDecoration: 'none',
                          color: theme.palette.primary.main,
                          fontWeight: 600
                        }}
                      >
                        Register here
                      </Link>
                    </Typography>
                    <Typography variant="body2" color="textSecondary" sx={{ mt: 1 }}>
                      <Link 
                        to="/forgot-password" 
                        style={{ 
                          textDecoration: 'none',
                          color: theme.palette.text.secondary,
                        }}
                      >
                        Forgot password?
                      </Link>
                    </Typography>
                  </Box>
                </motion.div>
              </Box>
            </Fade>
          </Paper>
        </Slide>
      </Container>
    </Box>
  );
};

export default Login;
